85\\t                target_collection: ledger.clone(),\\n1886\\t                target_id: EntityId::new(\\\"led-001\\\"),\\n1887\\t                link_type: \\\"relates-to\\\".into(),\\n1888\\t                metadata: serde_json::Value::Null,\\n1889\\t            },\\n1890\\t            Link {\\n1891\\t                source_collection: keep.clone(),\\n1892\\t                source_id: EntityId::new(\\\"keep-001\\\"),\\n1893\\t                target_collection: invoices.clone(),\\n1894\\t                target_id: EntityId::new(\\\"inv-001\\\"),\\n1895\\t                link_type: \\\"references\\\".into(),\\n1896\\t                metadata: serde_json::Value::Null,\\n1897\\t            },\\n1898\\t            Link {\\n1899\\t                source_collection: keep.clone(),\\n1900\\t                source_id: EntityId::new(\\\"keep-001\\\"),\\n1901\\t                target_collection: archive.clone(),\\n1902\\t                target_id: EntityId::new(\\\"arc-001\\\"),\\n1903\\t                link_type: \\\"references\\\".into(),\\n1904\\t                metadata: serde_json::Value::Null,\\n1905\\t            },\\n1906\\t        ] {\\n1907\\t            s.put_link(\u0026link).expect(\\\"link put should succeed\\\");\\n1908\\t        }\\n1909\\t\\n1910\\t        s.drop_namespace(\u0026billing)\\n1911\\t            .expect(\\\"billing drop should succeed\\\");\\n1912\\t\\n1913\\t        assert!(\\n1914\\t            s.list_inbound_links(\u0026ledger, \u0026EntityId::new(\\\"led-001\\\"), None)\\n1915\\t                .expect(\\\"ledger inbound links should load\\\")\\n1916\\t                .is_empty(),\\n1917\\t            \\\"links from removed collections must be purged\\\"\\n1918\\t        );\\n1919\\t        let keep_links = s\\n1920\\t            .list_outbound_links(\u0026keep, \u0026EntityId::new(\\\"keep-001\\\"), None)\\n1921\\t            .expect(\\\"keep outbound links should load\\\");\\n1922\\t        assert_eq!(keep_links.len(), 1);\\n1923\\t        assert_eq!(keep_links[0].target_collection, archive);\\n1924\\t    }\\n1925\\t\\n1926\\t    #[test]\\n1927\\t    fn drop_database_purges_entities_for_removed_collections() {\\n1928\\t        let _guard = postgres_test_guard();\\n1929\\t        let Some(mut s) = store_or_skip(\\\"drop_database_purges_entities_for_removed_collections\\\")\\n1930\\t        else {\\n1931\\t            return;\\n1932\\t        };\\n1933\\t        let analytics = Namespace::new(\\\"prod\\\", \\\"analytics\\\");\\n1934\\t        let orders = CollectionId::new(\\\"orders\\\");\\n1935\\t        let rollups = CollectionId::new(\\\"rollups\\\");\\n1936\\t        let keep = CollectionId::new(\\\"keep\\\");\\n1937\\t\\n1938\\t        s.create_database(\\\"prod\\\")\\n1939\\t            .expect(\\\"database create should succeed\\\");\\n1940\\t        s.create_namespace(\u0026analytics)\\n1941\\t            .expect(\\\"analytics namespace create should succeed\\\");\\n1942\\t        s.register_collection_in_namespace(\u0026orders, \u0026Namespace::new(\\\"prod\\\", \\\"default\\\"))\\n1943\\t            .expect(\\\"prod default collection register should succeed\\\");\\n1944\\t        s.register_collection_in_namespace(\u0026rollups, \u0026analytics)\\n1945\\t            .expect(\\\"analytics collection register should succeed\\\");\\n1946\\t        s.register_collection_in_namespace(\u0026keep, \u0026Namespace::default_ns())\\n1947\\t            .expect(\\\"default collection register should succeed\\\");\\n1948\\t        s.put(Entity::new(\\n1949\\t            orders.clone(),\\n1950\\t            EntityId::new(\\\"ord-001\\\"),\\n1951\\t            serde_json::json!({\\\"title\\\": \\\"order\\\"}),\\n1952\\t        ))\\n1953\\t        .expect(\\\"prod default entity put should succeed\\\");\\n1954\\t        s.put(Entity::new(\\n1955\\t            rollups.clone(),\\n1956\\t            EntityId::new(\\\"sum-001\\\"),\\n1957\\t            serde_json::json!({\\\"title\\\": \\\"rollup\\\"}),\\n195