       .entry(key)\\n701\\t                    .or_default()\\n702\\t                    .insert(entity_id.clone());\\n703\\t            }\\n704\\t        }\\n705\\t        Ok(())\\n706\\t    }\\n707\\t\\n708\\t    fn remove_index_entries(\\n709\\t        \u0026mut self,\\n710\\t        collection: \u0026CollectionId,\\n711\\t        entity_id: \u0026EntityId,\\n712\\t        data: \u0026serde_json::Value,\\n713\\t        indexes: \u0026[axon_schema::schema::IndexDef],\\n714\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n715\\t        let collection_key = self.resolve_catalog_key(collection)?;\\n716\\t        for idx in indexes {\\n717\\t            if let Some(val) = resolve_field_path(data, \u0026idx.field)\\n718\\t                .and_then(|v| extract_index_value(v, \u0026idx.index_type))\\n719\\t            {\\n720\\t                let key = (collection_key.clone(), idx.field.clone(), val);\\n721\\t                if let Some(set) = self.indexes.get_mut(\u0026key) {\\n722\\t                    set.remove(entity_id);\\n723\\t                    if set.is_empty() {\\n724\\t                        self.indexes.remove(\u0026key);\\n725\\t                    }\\n726\\t                }\\n727\\t            }\\n728\\t        }\\n729\\t        Ok(())\\n730\\t    }\\n731\\t\\n732\\t    fn index_lookup(\\n733\\t        \u0026self,\\n734\\t        collection: \u0026CollectionId,\\n735\\t        field: \u0026str,\\n736\\t        value: \u0026IndexValue,\\n737\\t    ) -\u003e Result\u003cVec\u003cEntityId\u003e, AxonError\u003e {\\n738\\t        let collection_key = self.resolve_catalog_key(collection)?;\\n739\\t        let key = (collection_key, field.to_string(), value.clone());\\n740\\t        Ok(self\\n741\\t            .indexes\\n742\\t            .get(\u0026key)\\n743\\t            .map(|set| set.iter().cloned().collect())\\n744\\t            .unwrap_or_default())\\n745\\t    }\\n746\\t\\n747\\t    fn index_range(\\n748\\t        \u0026self,\\n749\\t        collection: \u0026CollectionId,\\n750\\t        field: \u0026str,\\n751\\t        lower: Bound\u003c\u0026IndexValue\u003e,\\n752\\t        upper: Bound\u003c\u0026IndexValue\u003e,\\n753\\t    ) -\u003e Result\u003cVec\u003cEntityId\u003e, AxonError\u003e {\\n754\\t        let collection_key = self.resolve_catalog_key(collection)?;\\n755\\t        // Build range bounds for the BTreeMap key.\\n756\\t        let lower_key = match lower {\\n757\\t            Bound::Included(v) =\u003e {\\n758\\t                Bound::Included((collection_key.clone(), field.to_string(), v.clone()))\\n759\\t            }\\n760\\t            Bound::Excluded(v) =\u003e {\\n761\\t                Bound::Excluded((collection_key.clone(), field.to_string(), v.clone()))\\n762\\t            }\\n763\\t            Bound::Unbounded =\u003e {\\n764\\t                // Start from (collection, field, min-possible-value).\\n765\\t                // We use Included with a synthetic minimum key.\\n766\\t                Bound::Included((\\n767\\t                    collection_key.clone(),\\n768\\t                    field.to_string(),\\n769\\t                    IndexValue::Boolean(false),\\n770\\t                ))\\n771\\t            }\\n772\\t        };\\n773\\t        let upper_key = match upper {\\n774\\t            Bound::Included(v) =\u003e {\\n775\\t                Bound::Included((collection_key.clone(), field.to_string(), v.clone()))\\n776\\t            }\\n777\\t            Bound::Excluded(v) =\u003e {\\n778\\t                Bound::Excluded((collection_key.clone(), field.to_string(), v.clone()))\\n779\\t            }\\n780\\t            Bound::Unbounded =\u003e {\\n781\\t                // We need a key that is strictly after all values for this (collection, field).\\n782\\t                // Since field is a String, we append a char that sorts after all values.\\n783\\t                let mut upper_field = field.to_string();\\n784\\t                upper_field.push('\\\\x7f');\\n785\\t                Bound::Excluded((collection_key, upper_field, IndexValue::Boolean(false)))\\n786\\t            }\\n787\\t        };\\n788\\t\\n789\\t        let mut result = Vec::new();\\n790\\t        for ((_col, f, _val), ids) in self.indexes.range((lower_key, upper_key)) {\\n791\\t            if f != field {\\n792\\t                continue;\\n793\\t            }\\n794\\t            result.extend(ids.iter().cloned());\\n795\\t        }\\n796\\t        Ok(result)\\n797\\t    }\\n798\\t\\n799\\t    fn index_unique_conflict(\\n800\\t        \u0026self,\\n801\\t        collection: \u0026CollectionId,\\n802\\t        field: \u0026str,\\n803\\t        value: \u0026IndexValue,\\n804\\t        exclude_entity: \u0026EntityId,\\n805\\t    ) -\u003e Result\u003cbool, AxonError\u003e {\\n806\\t        let collection_key = self.resolve_catalog_key(collection)?;\\n807\\t        let key = (collection_key, field.to_string(), value.clone());\\n808\\t        Ok(self\\n809\\t            .indexes\\n810\\t            .get(\u0026key)\\n811\\t            .map(|set| set.iter().any(|eid| eid != exclude_entity))\\n812\\t            .unwrap_or(false))\\n813\\t    }\\n814\\t\\n815\\t    fn drop_indexes(\u0026mut self, collection: \u0026CollectionId) -\u003e Result\u003c(), AxonError\u003e {\\n816\\t        let key = self.resolve_catalog_key(collection)?;\\n817\\t        self.indexes.retain(|(col, _, _), _| col != \u0026key);\\n818\\t        self.compound_indexes.retain(|(col, _, _), _| col != \u0026key);\\n819\\t        Ok(())\\n820\\t    }\\n821\\t\\n822\\t    // ── Compound index operations (US-033) ──────────────────────────────\\n823\\t\\n824\\t    fn update_compound_indexes(\\n825\\t        \u0026mut self,\\n826\\t        collection: \u0026CollectionId,\\n827\\t        entity_id: \u0026EntityId,\\n828\\t        old_data: Option\u003c\u0026serde_json::Value\u003e,\\n829\\t        new_data: \u0026serde_json::Value,\\n830\\t        indexes: \u0026[axon_schema::schema::CompoundIndexDef],\\n831\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n832\\t        let collection_key = self.resolve_catalog_key(collection)?;\\n833\\t        // Remove old entries.\\n834\\t        if let Some(old) = old_data {\\n835\\t            for (idx_pos, idx) in indexes.iter().enumerate() {\\n836\\t                if let Some(key) = extract_compound_key(old, \u0026idx.fields) {\\n837\\t                    let ckey = (collection_key.clone(), idx_pos, key);\\n838\\t                    if let Some(set) = self.compound_indexes.get_mut(\u0026ckey) {\\n839\\t                        set.remove(entity_id);\\n840\\t                        if set.is_empty() {\\n841\\t                            self.compound_indexes.remove(\u0026ckey);\\n842\\t                        }\\n843\\t                    }\\n844\\t                }\\n845\\t            }\\n846\\t        }\\n847\\t\\n848\\t        // Insert new entries.\\n849\\t        for (idx_pos, idx) in indexes.iter().enumerate() {\\n850\\t            if let Some(key) = extract_compound_key(new_data, \u0026idx.fields) {\\n851\\t                if idx.unique {\\n852\\t                    let ckey = (collection_key.clone(), idx_pos, key.clone());\\n853\\t                    if let Some(existing) = self.compound_indexes.get(\u0026ckey) {\\n854\\t                        if existing.iter().any(|eid| eid != entity_id) {\\n855\\t                            let field_names: Vec\u003c\u0026str\u003e =\\n856\\t                                idx.fields.iter().map(|f| f.field.as_str()).collect();\\n857\\t                            return Err(AxonError::UniqueViolation {\\n858\\t                                field: field_names.join(\\\", \\\"),\\n859\\t                                value: format!(\\\"{key:?}\\\"),\\n860\\t                            });\\n861\\t                        }\\n862\\t                    }\\n863\\t                }\\n864\\t                let ckey = (collection_key.clone(), idx_pos, key);\\n865\\t                self.compound_indexes\\n866\\t                    .entry(ckey)\\n867\\t                    .or_default()\\n868\\t                    .insert(entity_id.clone());\\n869\\t            }\\n870\\t        }\\n871\\t        Ok(())\\n872\\t    }\\n873\\t\\n874\\t    fn remove_compound_index_entries(\\n875\\t        \u0026mut self,\\n876\\t        collection: \u0026CollectionId,\\n877\\t        entity_id: \u0026EntityId,\\n878\\t        data: \u0026serde_json::Value,\\n879\\t        indexes: \u0026[axon_schema::schema::CompoundIndexDef],\\n880\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n881\\t        let collection_key = self.resolve_catalog_key(collection)?;\\n882\\t        for (idx_pos, idx) in indexes.iter().enumerate() {\\n883\\t            if let Some(key) = extract_compound_key(data, \u0026idx.fields) {\\n884\\t                let ckey = (collection_key.clone(), idx_pos, key);\\n885\\t                if let Some(set) = self.compound_indexes.get_mut(\u0026ckey) {\\n886\\t                    set.remove(entity_id);\\n887\\t                    if set.is_empty() {\\n888\\t                        self.compound_indexes.remove(\u0026ckey);\\n889\\t                    }\\n890\\t                }\\n891\\t            }\\n892\\t        }\\n893\\t        Ok(())\\n894\\t    }\\n895\\t\\n896\\t    fn compound_index_lookup(\\n897\\t        \u0026self,\\n898\\t        collection: \u0026CollectionId,\\n899\\t        index_idx: usize,\\n900\\t        key: \u0026CompoundKey,\\n901\\t    ) -\u003e Result\u003cVec\u003cEntityId\u003e, AxonError\u003e {\\n902\\t        let collection_key = self.resolve_catalog_key(collection)?;\\n903\\t        let ckey = (collection_key, index_idx, key.clone());\\n904\\t        Ok(self\\n905\\t            .compound_indexes\\n906\\t            .get(\u0026ckey)\\n907\\t            .map(|set| set.iter().cloned().collect())\\n908\\t            .unwrap_or_default())\\n909\\t    }\\n910\\t\\n911\\t    fn compound_index_prefix(\\n912\\t        \u0026self,\\n913\\t       