ype: \u0026str,\\n958\\t        target_collection: \u0026CollectionId,\\n959\\t        target_id: \u0026EntityId,\\n960\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n961\\t        let key = (\\n962\\t            source_collection.clone(),\\n963\\t            source_id.clone(),\\n964\\t            link_type.to_string(),\\n965\\t            target_collection.clone(),\\n966\\t            target_id.clone(),\\n967\\t        );\\n968\\t        self.links.remove(\u0026key);\\n969\\t        // Also clean pseudo-collections for backward compatibility.\\n970\\t        let fwd_id = Link::storage_id(\\n971\\t            source_collection,\\n972\\t            source_id,\\n973\\t            link_type,\\n974\\t            target_collection,\\n975\\t            target_id,\\n976\\t        );\\n977\\t        let rev_id = Link::rev_storage_id(\\n978\\t            target_collection,\\n979\\t            target_id,\\n980\\t            source_collection,\\n981\\t            source_id,\\n982\\t            link_type,\\n983\\t        );\\n984\\t        self.delete(\u0026Link::links_collection(), \u0026fwd_id)?;\\n985\\t        self.delete(\u0026Link::links_rev_collection(), \u0026rev_id)\\n986\\t    }\\n987\\t\\n988\\t    fn get_link(\\n989\\t        \u0026self,\\n990\\t        source_collection: \u0026CollectionId,\\n991\\t        source_id: \u0026EntityId,\\n992\\t        link_type: \u0026str,\\n993\\t        target_collection: \u0026CollectionId,\\n994\\t        target_id: \u0026EntityId,\\n995\\t    ) -\u003e Result\u003cOption\u003cLink\u003e, AxonError\u003e {\\n996\\t        let key = (\\n997\\t            source_collection.clone(),\\n998\\t            source_id.clone(),\\n999\\t            link_type.to_string(),\\n1000\\t            target_collection.clone(),\\n1001\\t            target_id.clone(),\\n1002\\t        );\\n1003\\t        Ok(self.links.get(\u0026key).cloned())\\n1004\\t    }\\n1005\\t\\n1006\\t    fn list_outbound_links(\\n1007\\t        \u0026self,\\n1008\\t      