// TestDecompositionDepDirection verifies that instrStep0SizeCheck no longer
// instructs the agent to wire the parent into the dependency graph. The
// decomposition flow may still add legitimate child-to-child or sibling /
// replacement edges, but the parent itself must not be a dependency target.
func TestDecompositionDepDirection(t *testing.T) {
	correct := "legitimate child-to-child or sibling/replacement edges"
	wrong := "ddx bead dep add <parent-id> <child-id>"

	assert.True(t,
		strings.Contains(instrStep0SizeCheck, correct),
		"instrStep0SizeCheck must describe legitimate child-specific dependency edges", correct,
	)
	assert.False(t,
		strings.Contains(instrStep0SizeCheck, wrong),
		"instrStep0SizeCheck must not contain %q (parent-as-dependency back-edge)", wrong,
	)
}

// TestMixedCommitCooldown verifies that the circuit-breaker parks a bead to
// proposed after 2 mixed_commit_and_no_changes_rationale outcomes within 24h.
func TestMixedCommitCooldown(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))

	b := &bead.Bead{ID: "ddx-mixed-cb", Title: "Mixed commit circuit breaker test"}
	require.NoError(t, store.Create(context.

		// Append a prior mixed_commit execute-bead event (the 1st occurrence).
		Background(), b))

	require.NoError(t, store.AppendEvent("ddx-mixed-cb", bead.BeadEvent{
		Kind:      "execute-bead",
		Summary:   ExecuteBeadStatusExecutionFailed,
		Body:      mixedCommitAndNoChangesRationaleReason,
		Actor:     "test-worker",
		Source:    "ddx work",
		CreatedAt: time.Now().UTC().Add(-1 * time.Hour),
	}))

	var callCount int32
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			atomic.AddInt32(&callCount, 1)
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusExecutionFailed,
				Detail:    mixedCommitAndNoChangesRationaleReason,
				BaseRev:   "abc1111",
				ResultRev: "def2222",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "test-worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:         true,
		TargetBeadID: "ddx-mixed-cb",
	})
	require.NoError(t, err)
	require.Equal(t, int32(1), atomic.LoadInt32(&callCount), "executor must run exactly once")

	got, err := store.Get(context.Background(), "ddx-mixed-cb")
	require.NoError(t, err)
	assert.Equal(t, bead.StatusProposed, got.Status,
		"bead must be parked to proposed after 2nd mixed_commit within 24h")
}

func TestExecuteBeadLoop_NiflheimEvidence_DecomposedParentIsExecutionIneligible(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))

	parent := &bead.Bead{ID: "ddx-niflheim-parent", Title: "Niflheim decomposed parent"}
	require.NoError(t, store.Create(context.Background(), parent))

	decomp := &PreClaimDecomposition{
		Rationale: "split the parent after mixed-commit decomposition",
		Children: []PreClaimDecompositionChild{
			{Title: "Child A", Description: "child a", Acceptance: "1. do child a"},
			{Title: "Child B", Description: "child b", Acceptance: "1. do child b"},
		},
		ACMap: []ACMapEntry{
			{ParentAC: "1. split the parent", Coverage: "covered by Child A"},
			{ParentAC: "2. keep the parent out of the ready queue", Coverage: "covered by Child B"},
		},
	}

	var execCalls int32
	var escalationCalls int32
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			atomic.AddInt32(&execCalls, 1)
			return ExecuteBeadReport{
				BeadID:             beadID,
				Status:             ExecuteBeadStatusExecutionFailed,
				Detail:             mixedCommitAndNoChangesRationaleReason,
				BaseRev:            "base-niflheim",
				ResultRev:          "result-niflheim",
				NoChangesRationale: "status: open\norchestrator_action: decompose\nreason: split the parent",
			}, nil
		}),
		EscalationNextFloor: func(actualPower int) (int, error) {
			atomic.AddInt32(&escalationCalls, 1)
			return actualPower + 1, nil
		},
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker", MaxDecompositionDepth: 3}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	runtime := ExecuteBeadLoopRuntime{
		Once:         true,
		TargetBeadID: parent.ID,
		PostAttemptTriageHook: func(ctx context.Context, beadID string, report ExecuteBeadReport) (TriageResult, error) {
			return TriageResult{
				Classification:    "decomposed",
				RecommendedAction: "close_decomposed_or_mark_execution_ineligible",
				Rationale:         "parent split already exists",
			}, nil
		},
		PostAttemptDecompositionHook: func(ctx context.Context, beadID string) (*PreClaimDecomposition, error) {
			return decomp, nil
		},
	}

	result, err := worker.Run(context.Background(), rcfg, runtime)
	require.NoError(t, err)
	require.Equal(t, int32(1), atomic.LoadInt32(&execCalls), "executor must run exactly once")
	assert.Zero(t, atomic.LoadInt32(&escalationCalls), "decomposed parents must not schedule min-power escalation")
	require.Len(t, result.Results, 1, "the worker must emit one report for the decomposed parent attempt")
	assert.Equal(t, "decomposed", result.Results[0].OutcomeReason)
	assert.Len(t, result.Results[0].DecomposedChildIDs, 2, "the report must carry the created child bead IDs")
	require.Len(t, result.Results[0].CycleTrace, 1, "the worker must capture one execution cycle")
	assert.Len(t, result.Results[0].CycleTrace[0].DecomposedChildIDs, 2, "the cycle trace must carry the created child bead IDs")

	got, err := store.Get(context.Background(), parent.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status, "decomposed parent must stay open")
	assert.Equal(t, false, got.Extra[bead.ExtraExecutionElig], "decomposed parent must be execution-ineligible")

	events, err := store.Events(parent.ID)
	require.NoError(t, err)
	foundDecomposition := false
	for _, ev := range events {
		if ev.Kind != "triage-decomposed" {
			continue
		}
		foundDecomposition = true
		assert.Contains(t, ev.Body, `"child_ids"`, "decomposition event must record child IDs")
	}
	assert.True(t, foundDecomposition, "post-attempt decomposition must record a triage-decomposed event")

	var executeEvent *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "execute-bead" {
			executeEvent = &events[i]
			break
		}
	}
	require.NotNil(t, executeEvent, "the decomposed parent attempt must still append an execute-bead event")
	assert.Contains(t, executeEvent.Body, `"decomposed_child_ids"`, "execute-bead event body must carry child IDs in the decision audit")
	assert.Contains(t, executeEvent.Body, "outcome_reason=decomposed", "execute-bead event body must preserve the decomposed outcome reason")

	children, err := store.ReadAll(context.Background())
	require.NoError(t, err)
	childCount := 0
	for i := range children {
		if children[i].Parent != parent.ID {
			continue
		}
		childCount++
		assert.Equal(t, parent.ID, children[i].Parent, "child must reference the decomposed parent")
	}
	assert.Equal(t, 2, childCount, "post-attempt decomposition must create both child beads")

	_, err = worker.Run(context.Background(), rcfg, runtime)
	require.NoError(t, err)
	assert.Equal(t, int32(1), atomic.LoadInt32(&execCalls), "parent must not be re-claimed after parking")
}

func TestWorkRetryEscalation_NiflheimEvidence_DecomposedParentDoesNotRaiseMinPower(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))

	parent := &bead.Bead{ID: "ddx-niflheim-retry-parent", Title: "Niflheim retry escalation parent"}
	require.NoError(t, store.Create(context.Background(), parent))

	decomp := &PreClaimDecomposition{
		Rationale: "split the parent after mixed-commit decomposition",
		Children: []PreClaimDecompositionChild{
			{Title: "Retry Child A", Description: "child a", Acceptance: "1. do child a"},
			{Title: "Retry Child B", Description: "child b", Acceptance: "1. do child b"},
		},
		ACMap: []ACMapEntry{
			{ParentAC: "1. split the parent", Coverage: "covered by Retry Child A"},
			{ParentAC: "2. keep the parent out of the ready queue", Coverage: "covered by Retry Child B"},
		},
	}

	var execCalls int32
	var minPowerCalls int32
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			atomic.AddInt32(&execCalls, 1)
			return ExecuteBeadReport{
				BeadID:             beadID,
				Status:             ExecuteBeadStatusExecutionFailed,
				Detail:             mixedCommitAndNoChangesRationaleReason,
				BaseRev:            "base-niflheim",
				ResultRev:          "result-niflheim",
				RequestedProfile:   "default",
				InferredPowerClass: "standard",
				PowerClass:         "standard",
				NoChangesRationale: "status: open\norchestrator_action: decompose\nreason: split the parent",
			}, nil
		}),
		EscalationNextFloor: func(actualPower int) (int, error) {
			atomic.AddInt32(&minPowerCalls, 1)
			return actualPower + 1, nil
		},
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker", MaxDecompositionDepth: 3}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	runtime := ExecuteBeadLoopRuntime{
		Once:         true,
		TargetBeadID: parent.ID,
		PostAttemptTriageHook: func(ctx context.Context, beadID string, report ExecuteBeadReport) (TriageResult, error) {
			return TriageResult{
				Classification:    "decomposed",
				RecommendedAction: "close_decomposed_or_mark_execution_ineligible",
				Rationale:         "parent split already exists",
			}, nil
		},
		PostAttemptDecompositionHook: func(ctx context.Context, beadID string) (*PreClaimDecomposition, error) {
			return decomp, nil
		},
	}

	result, err := worker.Run(context.Background(), rcfg, runtime)
	require.NoError(t, err)
	require.NotNil(t, result)

package agent

import (
	"bufio"
	"context"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"regexp"
	"strconv"
	"strings"
	"time"

	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
)

// runScriptFn executes a directive file against opts.WorkDir using real filesystem
// and git operations. The directive file path is taken from opts.Model (if it is
// a readable file) or from opts.PromptFile as a fallback.
func runScriptFn(r *Runner, opts RunArgs) (*Result, error) {
	start := time.Now()

	// Resolve directive file: opts.Model first, then opts.PromptFile.
	directivePath := opts.Model
	if directivePath == "" || !isReadableFile(directivePath) {
		if opts.PromptFile != "" {
			directivePath = opts.PromptFile
		}
	}
	if directivePath == "" {
		return nil, fmt.Errorf("script harness: no directive file (set --model or --prompt-file)")
	}

	data, err := os.ReadFile(directivePath)
	if err != nil {
		return nil, fmt.Errorf("script harness: read directive file %s: %w", directivePath, err)
	}

	workDir := opts.WorkDir
	if workDir == "" {
		workDir = "."
	}

	var outputLines []string
	exitCode := 0
	var execErr error

	directives := parseDirectives(string(data))

	// Build env interpolation map from the process/runtime environment, with
	// correlation as the most specific source when execute-bead provides it.
	envMap := map[string]string{
		"DDX_BEAD_ID":         os.Getenv("DDX_BEAD_ID"),
		"DDX_ATTEMPT_ID":      os.Getenv("DDX_ATTEMPT_ID"),
		"DDX_WORKER_ID":       os.Getenv("DDX_WORKER_ID"),
		"DDX_SESSION_LOG_DIR": os.Getenv("DDX_SESSION_LOG_DIR"),
	}
	for k, v := range opts.Env {
		if strings.HasPrefix(k, "DDX_") {
			envMap[k] = v
		}
	}
	if opts.SessionLogDir != "" {
		envMap["DDX_SESSION_LOG_DIR"] = opts.SessionLogDir
	}
	if opts.Correlation != nil {
		if v, ok := opts.Correlation["bead_id"]; ok {
			envMap["DDX_BEAD_ID"] = v
		}
		if v, ok := opts.Correlation["attempt_id"]; ok {
			envMap["DDX_ATTEMPT_ID"] = v
		}
		if v, ok := opts.Correlation["worker_id"]; ok {
			envMap["DDX_WORKER_ID"] = v
		}
	}
	expand := func(s string) string {
		return os.Expand(s, func(key string) string {
			return envMap[key]
		})
	}

	for i, d := range directives {
		verb := d[0]
		args := d[1:]

		switch verb {
		case "no-op":
			outputLines = append(outputLines, "no-op")

		case "set-exit":
			if len(args) < 1 {
				execErr = fmt.Errorf("script harness: set-exit requires an argument")
				goto done
			}
			n, err := strconv.Atoi(args[0])
			if err != nil {
				execErr = fmt.Errorf("script harness: set-exit: invalid code %q", args[0])
				goto done
			}
			exitCode = n

		case "sleep-ms":
			if len(args) < 1 {
				execErr = fmt.Errorf("script harness: sleep-ms requires an argument")
				goto done
			}
			n, err := strconv.Atoi(args[0])
			if err != nil {
				execErr = fmt.Errorf("script harness: sleep-ms: invalid duration %q", args[0])
				goto done
			}
			time.Sleep(time.Duration(n) * time.Millisecond)

		case "fail-during":
			if len(args) < 1 {
				execErr = fmt.Errorf("script harness: fail-during requires an argument")
				goto done
			}
			n, err := strconv.Atoi(args[0])
			if err != nil {
				execErr = fmt.Errorf("script harness: fail-during: invalid index %q", args[0])
				goto done
			}
			if i == n {
				execErr = fmt.Errorf("script harness: synthetic failure at directive %d", i)
				goto done
			}

		case "append-line":
			if len(args) < 2 {
				execErr = fmt.Errorf("script harness: append-line requires path and text")
				goto done
			}
			path, err := resolvePath(workDir, expand(args[0]))
			if err != nil {
				execErr = err
				goto done
			}
			text := expand(strings.Join(args[1:], " "))
			if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
				execErr = fmt.Errorf("script harness: append-line mkdir: %w", err)
				goto done
			}
			f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
			if err != nil {
				execErr = fmt.Errorf("script harness: append-line open: %w", err)
				goto done
			}
			_, werr := fmt.Fprintln(f, text)
			f.Close()
			if werr != nil {
				execErr = fmt.Errorf("script harness: append-line write: %w", werr)
				goto done
			}
			outputLines = append(outputLines, fmt.Sprintf("append-line %s", args[0]))

		case "create-file":
			if len(args) < 2 {
				execErr = fmt.Errorf("script harness: create-file requires path and content")
				goto done
			}
			path, err := resolvePath(workDir, expand(args[0]))
			if err != nil {
				execErr = err
				goto done
			}
			content := expand(strings.Join(args[1:], " "))
			if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
				execErr = fmt.Errorf("script harness: create-file mkdir: %w", err)
				goto done
			}
			if err := os.WriteFile(path, []byte(content), 0644); err != nil {
				execErr = fmt.Errorf("script harness: create-file write: %w", err)
				goto done
			}
			outputLines = append(outputLines, fmt.Sprintf("create-file %s", args[0]))

		case "delete-file":
			if len(args) < 1 {
				execErr = fmt.Errorf("script harness: delete-file requires a path")
				goto done
			}
			path, err := resolvePath(workDir, expand(args[0]))
			if err != nil {
				execErr = err
				goto done
			}
			if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
				execErr = fmt.Errorf("script harness: delete-file: %w", err)
				goto done
			}
			outputLines = append(outputLines, fmt.Sprintf("delete-file %s", args[0]))

		case "modify-line":
			if len(args) < 3 {
				execErr = fmt.Errorf("script harness: modify-line requires path, regex, and replacement")
				goto done
			}
			path, err := resolvePath(workDir, expand(args[0]))
			if err != nil {
				execErr = err
				goto done
			}
			pattern := expand(args[1])
			repl := expand(strings.Join(args[2:], " "))
			re, err := regexp.Compile(pattern)
			if err != nil {
				execErr = fmt.Errorf("script harness: modify-line: bad regex %q: %w", pattern, err)
				goto done
			}
			raw, err := os.ReadFile(path)
			if err != nil {
				execErr = fmt.Errorf("script harness: modify-line read: %w", err)
				goto done
			}
			lines := strings.Split(string(raw), "\n")
			for li, line := range lines {
				if re.MatchString(line) {
					lines[li] = re.ReplaceAllString(line, repl)
					break
				}
			}
			if err := os.WriteFile(path, []byte(strings.Join(lines, "\n")), 0644); err != nil {
				execErr = fmt.Errorf("script harness: modify-line write: %w", err)
				goto done
			}
			outputLines = append(outputLines, fmt.Sprintf("modify-line %s", args[0]))

		case "run":
			if len(args) < 1 {
				execErr = fmt.Errorf("script harness: run requires a shell command")
				goto done
			}
			shell := expand(strings.Join(args, " "))
			cmd := exec.Command("sh", "-c", shell)
			cmd.Dir = workDir
			cmd.Env = envWithOverrides(scrubbedGitEnvScript(), opts.Env)
			out, err := cmd.CombinedOutput()
			outputLines = append(outputLines, strings.TrimRight(string(out), "\n"))
			if err != nil {
				execErr = fmt.Errorf("script harness: run %q: %w", shell, err)
				goto done
			}

		case "commit":
			if len(args) < 1 {
				execErr = fmt.Errorf("script harness: commit requires a message")
				goto done
			}
			msg := expand(strings.Join(args, " "))
			if err := gitCommitAll(workDir, msg, opts.Env); err != nil {
				execErr = fmt.Errorf("script harness: commit: %w", err)
				goto done
			}
			outputLines = append(outputLines, fmt.Sprintf("commit %q", msg))

		default:
			execErr = fmt.Errorf("script harness: unknown directive %q at index %d", verb, i)

package bead

import (
	"crypto/sha1"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

const claimLivenessNamespace = "ddx-claim-heartbeats"

// claimLeaseSameMachineFallbackAge is the hard ceiling after which a same
// machine + live PID lease stops blocking takeover and we fall back to age.
// It stays comfortably above the lock-hold caps enforced elsewhere.
const claimLeaseSameMachineFallbackAge = 2 * time.Hour

type ClaimLeaseRecord struct {
	BeadID    string    `json:"bead_id"`
	Owner     string    `json:"owner,omitempty"`
	Session   string    `json:"session,omitempty"`
	Worktree  string    `json:"worktree,omitempty"`
	Machine   string    `json:"machine,omitempty"`
	StartedAt time.Time `json:"started_at,omitempty"`
	UpdatedAt time.Time `json:"updated_at"`
	PID       int       `json:"pid,omitempty"`
}

func claimLivenessPath(ddxDir, id string) string {
	root := canonicalClaimRoot(ddxDir)
	sum := sha1.Sum([]byte(root))
	return filepath.Join(os.TempDir(), claimLivenessNamespace, hex.EncodeToString(sum[:]), id+".json")
}

func canonicalClaimRoot(ddxDir string) string {
	root := filepath.Clean(filepath.Dir(ddxDir))
	if abs, err := filepath.Abs(root); err == nil {
		root = abs
	}
	if real, err := filepath.EvalSymlinks(root); err == nil {
		root = real
	}
	return filepath.Clean(root)
}

func currentMachineID() string {
	machine, _ := os.Hostname()
	if envID := os.Getenv("DDX_MACHINE_ID"); envID != "" {
		machine = envID
	}
	return machine
}

func writeAtomicClaimFile(path string, data []byte) error {
	dir := filepath.Dir(path)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("bead: mkdir claim liveness dir: %w", err)
	}
	tmp, err := os.CreateTemp(dir, filepath.Base(path)+".tmp-*")
	if err != nil {
		return fmt.Errorf("bead: create claim liveness tmp: %w", err)
	}
	tmpName := tmp.Name()
	defer func() {
		_ = tmp.Close()
		_ = os.Remove(tmpName)
	}()
	if _, err := tmp.Write(data); err != nil {
		return fmt.Errorf("bead: write claim liveness tmp: %w", err)
	}
	if err := tmp.Close(); err != nil {
		return fmt.Errorf("bead: close claim liveness tmp: %w", err)
	}
	if err := os.Rename(tmpName, path); err != nil {
		return fmt.Errorf("bead: publish claim liveness: %w", err)
	}
	return nil
}

func (s *Store) writeClaimHeartbeat(rec ClaimLeaseRecord) error {
	data, err := json.Marshal(rec)
	if err != nil {
		return fmt.Errorf("bead: marshal claim liveness: %w", err)
	}
	data = append(data, '\n')
	return writeAtomicClaimFile(claimLivenessPath(s.Dir, rec.BeadID), data)
}

func (s *Store) readClaimHeartbeat(id string) (ClaimLeaseRecord, bool, error) {
	data, err := os.ReadFile(claimLivenessPath(s.Dir, id))
	if os.IsNotExist(err) {
		return ClaimLeaseRecord{}, false, nil
	}
	if err != nil {
		return ClaimLeaseRecord{}, false, fmt.Errorf("bead: read claim liveness: %w", err)
	}
	var rec ClaimLeaseRecord
	if err := json.Unmarshal(data, &rec); err != nil {
		return ClaimLeaseRecord{}, true, fmt.Errorf("bead: parse claim liveness: %w", err)
	}
	return rec, true, nil
}

func (s *Store) upsertClaimHeartbeat(id string, mutate func(*ClaimLeaseRecord)) error {
	rec, found, err := s.readClaimHeartbeat(id)
	if err != nil {
		return err
	}
	now := time.Now().UTC()
	if !found {
		rec = ClaimLeaseRecord{
			BeadID:    id,
			StartedAt: now,
		}
	}
	if rec.BeadID == "" {
		rec.BeadID = id
	}

		if err := w.Store.AppendNotes(candidate.ID, preservedNeedsReviewNote(report)); err != nil {
			_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
				return commitOutcomeError("AppendNotes", assignee, result, err)
			})
			if ctx.Err() != nil {
				return executeBeadIterationOutcome{Stop: true}, ctx.Err()
			}
			return executeBeadIterationOutcome{Continue: true}, nil
		}
		result.Failures++
		result.LastFailureStatus = report.Status
	} else if report.Status == ExecuteBeadStatusRepairCycleExhausted {
		if err := applyRepairCycleExhaustedEscalation(w.Store, candidate.ID, assignee, report.ActualPower, now(), w.EscalationNextFloor); err != nil {
			_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
				return commitOutcomeError("applyRepairCycleExhaustedEscalation", assignee, result, err)
			})
			if ctx.Err() != nil {
				return executeBeadIterationOutcome{Stop: true}, ctx.Err()
			}
			return executeBeadIterationOutcome{Continue: true}, nil
		}
		result.Failures++
		result.LastFailureStatus = report.Status
	} else if report.Status == ExecuteBeadStatusLandRetry {
		report.OutcomeReason = FailureModeLandRetry
		report.Disrupted = true
		report.DisruptionReason = FailureModeLandRetry
		_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
			Kind:    "land-coordination",
			Summary: "retry-land",
			Body: strings.Join([]string{
				"action=retry-land",
				"detail=" + report.Detail,
				"result_rev=" + report.ResultRev,
				"base_rev=" + report.BaseRev,
				decisionAuditEventBodyLine(report),
			}, "\n"),
			Actor:     assignee,
			Source:    "ddx work",
			CreatedAt: now().UTC(),
		})
		result.Failures++
		result.LastFailureStatus = report.Status
	} else if report.Status == ExecuteBeadStatusLandOperatorAttention {
		report.OutcomeReason = FailureModeLandOperatorAttention
		reason := report.Detail
		if strings.TrimSpace(reason) == "" {
			reason = FailureModeLandOperatorAttention
		}
		if parkErr := parkToProposedSimple(w.Store, candidate.ID, bead.ParkAutoRecoveryFailed, reason, now().UTC()); parkErr != nil && runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "land coordination operator-attention park failed for %s: %v (continuing)\n", candidate.ID, parkErr)
		}
		_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
			Kind:    "operator_attention",
			Summary: FailureModeLandOperatorAttention,
			Body: strings.Join([]string{
				"action=operator-attention",
				"detail=" + report.Detail,
				"result_rev=" + report.ResultRev,
				"base_rev=" + report.BaseRev,
				decisionAuditEventBodyLine(report),
			}, "\n"),
			Actor:     assignee,
			Source:    "ddx work",
			CreatedAt: now().UTC(),
		})
		result.Failures++
		result.LastFailureStatus = report.Status
	} else {
		if isProviderConnectivityFailureReport(report) {
			report.OutcomeReason = FailureModeProviderConnectivity
			report.Disrupted = true
			report.DisruptionReason = "provider_connectivity"
			operatorPinned := isOperatorRoutingPinned(rcfg.Passthrough())
			if err := applyProviderConnectivityRouteExclusion(w.Store, candidate.ID, assignee, report, operatorPinned, w.EscalationNextFloor, now().UTC()); err != nil {
				if runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log, "route-exclusion update failed for %s: %v (continuing)\n", candidate.ID, err)
				}
			}
			emitRouteFailureEvent(w.Store, candidate.ID, assignee, report, now().UTC())
			// Route exclusion (TTL-based via RouteExclusionWindow) is the
			// correct mechanism — no per-bead cooldown. Bead is immediately
			// reclaimable; next attempt routes around the failed (provider,model).
		} else if isNoViableProviderReport(report) {
			report.OutcomeReason = FailureModeNoViableProvider
			report.Disrupted = true
			report.DisruptionReason = "no_viable_provider"
			serverOutageActivated := false
			if activated, _ := serverOutage.Record(report, candidate.ID, now().UTC()); activated {
				serverOutageActivated = true
				pausedInfraUntil = time.Time{}
			} else {
				// Transition the worker to paused-infra: leave every bead
				// immediately reclaimable, pause this worker for PausedInfraInterval,
				// then re-evaluate the full queue (P6 + ADR-024 §Infra Fallback).
				pausedInfraUntil = now().UTC().Add(PausedInfraInterval)
			}
			if loopMode == executeloop.ModeWatch {
				if !serverOutageActivated {
					transientCandidateSkips[candidate.ID] = routingUnavailableSkipReason
				}
				return executeBeadIterationOutcome{Continue: true}, nil
			}
		} else {
			serverOutageActivated := false
			if activated, _ := serverOutage.Record(report, candidate.ID, now().UTC()); activated {
				serverOutageActivated = true
				pausedInfraUntil = time.Time{}
			}
			if !serverOutageActivated {
				report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
				if report.Detail == mixedCommitAndNoChangesRationaleReason && report.NoChangesRationale != "" {
					parsed := ParseNoChangesRationale(report.NoChangesRationale)
					if parsed.OrchestratorAction == "decompose" {
						report.OutcomeReason = "decomposed"
						if runtime.PostAttemptDecompositionHook != nil {
							if childIDs, backEdgeDetected := w.handlePostAttemptDecomposition(ctx, &candidate, runtime, assignee, rcfg, now().UTC()); len(childIDs) > 0 {
								report.DecomposedChildIDs = append([]string(nil), childIDs...)
								if backEdgeDetected {
									sawParentBackEdge = true
								}
							} else if backEdgeDetected {
								sawParentBackEdge = true
